const body = $json.body ?? $json;
const providerReference = body.providerReference ?? body.reference ?? body.transactionId ?? '';
const status = String(body.status ?? body.transactionStatus ?? '').toLowerCase();
const correlationId = body.correlationId ?? '';

if (!providerReference) {
  throw new Error('providerReference is required');
}

const approved = ['approved', 'paid', 'success', 'succeeded'].includes(status);

return [{
  json: {
    success: true,
    provider: 'bancolombia',
    providerReference,
    status: approved ? 'approved' : status || 'processing',
    approved,
    correlationId,
    ackAt: new Date().toISOString(),
    message: approved
      ? 'Pago confirmado por callback.'
      : 'Callback recibido y pendiente de conciliación.'
  }
}];
